import unreal
# Spawn a cube at origin
location = unreal.Vector(0, 0, 100)
rotation = unreal.Rotator(0, 0, 0)
actor = unreal.EditorLevelLibrary.spawn_actor_from_class(
    unreal.StaticMeshActor, location, rotation
)
if actor:
    mesh = unreal.EditorAssetLibrary.load_asset('/Engine/BasicShapes/Cube')
    actor.static_mesh_component.set_static_mesh(mesh)
    actor.set_actor_label('TrainingCube')
    __bridge_result__ = {'spawned': True, 'label': 'TrainingCube'}
else:
    __bridge_result__ = {'spawned': False}

